import ast, pathlib, json, os, torch
for fn in ['model.py','predict.py']:
    src=pathlib.Path(fn).read_text()
    tree=ast.parse(src)
    print('###',fn)
    names={'default_params','HeuristicPolicy','make_action','planner_hint','run_episode','get_gps','main','make_env'}
    for node in tree.body:
        if isinstance(node,(ast.FunctionDef, ast.ClassDef)) and node.name in names:
            lines=src.splitlines()[node.lineno-1:node.end_lineno]
            if node.name in {'make_env','main'} and len(lines)>45:
                lines=lines[:45]+['    ...TRUNC...']
            print(f'--- {node.name} lines {node.lineno}-{node.end_lineno} ---')
            print('\n'.join(lines[:120]))
ck='checkpoints/baseline/model.pt'
print('### CKPT')
try:
    d=torch.load(ck,map_location='cpu')
    print(json.dumps(d.get('params',{}),sort_keys=True))
except Exception as e: print('ERR',e)
for p in ['logs/iter_23/agent1_control.json','logs/iter_17/sweep_params.json']:
    print('###',p)
    try:
        data=json.load(open(p))
        if isinstance(data,list):
            from collections import defaultdict
            g=defaultdict(list)
            for r in data: g[r.get('mode','?')].append(r)
            for k,rows in g.items():
                print(k, 'n',len(rows),'succ',sum(r.get('succ',0) for r in rows)/len(rows),'safe',sum(r.get('safe',0) for r in rows)/len(rows),'latch',sum(r.get('latch_step',0) for r in rows)/len(rows))
        elif isinstance(data,dict):
            print(json.dumps(data.get('summary',data)[:8] if isinstance(data.get('summary',data),list) else data, indent=2)[:3500])
    except Exception as e: print('ERR',e)
